import mysql.connector
import os
from mysql.connector import Error

def secure_mysql_import():
    try:
        # Get file path from user input
        file_path = input("Enter the CSV file path to import: ").strip()
        
        # Validate file path
        if not file_path:
            raise ValueError("File path cannot be empty")
            
        # Check if file exists
        if not os.path.exists(file_path):
            raise FileNotFoundError(f"File not found: {file_path}")
            
        # Validate file extension
        if not file_path.lower().endswith(('.csv', '.txt')):
            raise ValueError("Only CSV and TXT files are allowed")
            
        # Connect to MySQL with local_infile enabled
        connection = mysql.connector.connect(
            host='localhost',
            database='your_database',
            user='your_username',
            password='your_password',
            autocommit=True,
            allow_local_infile=True
        )
        
        cursor = connection.cursor()
        
        # Prepare SQL statement with parameterized file path
        table_name = "your_table_name"
        sql_query = f"""
        LOAD DATA INFILE '{file_path}' 
        INTO TABLE {table_name}
        FIELDS TERMINATED BY ',' 
        ENCLOSED BY '"'
        LINES TERMINATED BY '\\n'
        IGNORE 1 ROWS
        """
        
        # Execute the query
        cursor.execute(sql_query)
        print(f"Successfully imported data from {file_path}")
        
    except Error as e:
        print(f"Database error: {e}")
    except FileNotFoundError as e:
        print(f"File error: {e}")
    except ValueError as e:
        print(f"Validation error: {e}")
    except Exception as e:
        print(f"Unexpected error: {e}")
    finally:
        # Clean up connections
        if 'cursor' in locals():
            cursor.close()
        if 'connection' in locals() and connection.is_connected():
            connection.close()

# Run the function
if __name__ == "__main__":
    secure_mysql_import()